module div_8bit (
    input clk,
    input rst,
    input sign,
    input [7:0] dividend,
    input [7:0] divisor,
    input opn_valid,
    input res_ready,
    output reg res_valid,
    output reg [15:0] result
);
    reg [7:0] dividend_reg;
    reg [7:0] divisor_reg;
    reg [15:0] sr;
    reg [7:0] neg_divisor;
    reg [3:0] cnt;
    reg start_cnt;

    always @(posedge clk or negedge rst) begin
        if (!rst) begin
            dividend_reg <= 8'b0;
            divisor_reg <= 8'b0;
            sr <= 16'b0;
            neg_divisor <= 8'b0;
            cnt <= 4'b0;
            start_cnt <= 1'b0;
            res_valid <= 1'b0;
            result <= 16'b0;
        end else begin
            if (opn_valid && !res_valid) begin
                dividend_reg <= dividend;
                divisor_reg <= divisor;
                sr <= {dividend_reg, 8'b0};
                neg_divisor <= $signed(~divisor_reg) + 1;
                cnt <= 4'b1;
                start_cnt <= 1'b1;
            end

            if (start_cnt) begin
                if (cnt == 4'b1000) begin
                    cnt <= 4'b0;
                    start_cnt <= 1'b0;
                    sr <= {sr[15:8], sr[7:0]};
                    result <= {sr[15:8], sr[7:0]};
                end else begin
                    cnt <= cnt + 1;
                    sr <= {sr[15:8], sr[7:0]} - {neg_divisor, 8'b0};
                end
            end

            if (res_valid && res_ready) begin
                res_valid <= 1'b0;
            end else if (res_valid) begin
                res_valid <= 1'b1;
            end
        end
    end

endmodule
